import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Activation Guide","description":"","frontmatter":{"title":"Activation Guide","slug":"activation-guide"},"headers":[],"relativePath":"marketer-hub/activation-guide.md","filePath":"marketer-hub/activation-guide.md"}'),r={name:"marketer-hub/activation-guide.md"};function n(s,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>With Branch Activation, you can create shortened Web and App Links (with custom QR codes) that work everywhere.</p><h3 id="how-branch-links-work" tabindex="-1">How Branch Links work <a class="header-anchor" href="#how-branch-links-work" aria-label="Permalink to &quot;How Branch Links work&quot;">​</a></h3><p>Web Links are web-only Short Links that work everywhere. App Links are deep links that take users to specific pages in your app. Web and App Links look the same (yourbrand.com/slug or yourbrand.app.link/slug) depending on if you choose to use a custom domain or a Branch-provided app.link domain.</p><h4 id="expected-behavior-for-web-links" tabindex="-1">Expected behavior for Web Links <a class="header-anchor" href="#expected-behavior-for-web-links" aria-label="Permalink to &quot;Expected behavior for Web Links&quot;">​</a></h4><p>If your end user does <strong>not</strong> have your app installed, or if you don’t have an app, the link will open in their default web browser. If they do have your app downloaded, the link will open in your app through an in-app web view.</p><h4 id="expected-behavior-for-app-links" tabindex="-1">Expected behavior for App Links <a class="header-anchor" href="#expected-behavior-for-app-links" aria-label="Permalink to &quot;Expected behavior for App Links&quot;">​</a></h4><p>If your end user has your app installed, the App Link will deep link to the specific app page you’ve chosen. If they do <strong>not</strong> have your app installed, they will taken to the redirect destination for non-app users which can be configured as a web page, a Branch Deepview, or the app store listing to download the app.</p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>You can set up a custom domain in the Branch Dashboard or you can use the Branch-provided app.link domain. If you want to create App Short Links, you must <strong>integrate the Branch SDK</strong> into your app(s). If you only want to create Web Short Links that go to an internet browser, no additional setup is required.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>For now, you can only configure one custom domain. However, we will add support for multiple custom domains in the future.</p></div><h3 id="set-up-a-custom-domain-optional" tabindex="-1">Set up a custom domain (optional) <a class="header-anchor" href="#set-up-a-custom-domain-optional" aria-label="Permalink to &quot;Set up a custom domain (optional)&quot;">​</a></h3><p>Before you use Activation features, you can set up a custom domain (for example, link.yourbrand.com) in the Branch Dashboard. Read our <a href="./advanced-settings-configuration.html">Advanced Settings &amp; Changing Link Domain</a> article to learn how.</p><p>After you set up your custom domain, you can use it to create branded Web Short Links.</p><h3 id="set-up-deep-linking-and-app-integration-optional" tabindex="-1">Set up deep linking and app integration (optional) <a class="header-anchor" href="#set-up-deep-linking-and-app-integration-optional" aria-label="Permalink to &quot;Set up deep linking and app integration (optional)&quot;">​</a></h3><p>To create App Short Links using Activation, you must integrate the Branch SDK into your app(s). You must also have the latest version of the Branch SDK installed for in-app web views to work.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you don’t want to create App Short Links to deep link to your app or show an in-app web view for Web Short Links, you can skip this setup.</p></div><p>Read the following articles to learn more:</p><ul><li><a href="https://help.branch.io/developers-hub/docs/native-sdks-overview" target="_blank" rel="noreferrer">Branch SDK Overview</a></li><li><a href="https://help.branch.io/developers-hub/docs/ios-sdk-overview" target="_blank" rel="noreferrer">Branch iOS SDK Overview</a></li><li><a href="https://help.branch.io/developers-hub/docs/android-sdk-overview" target="_blank" rel="noreferrer">Branch Android SDK Overview</a></li></ul><h2 id="create-a-web-short-link" tabindex="-1">Create a Web Short Link <a class="header-anchor" href="#create-a-web-short-link" aria-label="Permalink to &quot;Create a Web Short Link&quot;">​</a></h2><p>Web Short Links are web-only Short Links that work everywhere.</p><h3 id="step-1-start-creating-link" tabindex="-1">Step 1: Start creating link <a class="header-anchor" href="#step-1-start-creating-link" aria-label="Permalink to &quot;Step 1: Start creating link&quot;">​</a></h3><p>Complete the following steps to start creating a link:</p><ol><li>In the Branch Dashboard, select the <strong>Create</strong> button in the top-right corner of the page.</li><li>Select <strong>Link</strong>.</li><li>Select <strong>Short Link</strong>. The <strong>Create Short Link</strong> page will open.</li></ol><h3 id="step-2-define-your-web-short-link" tabindex="-1">Step 2: Define your Web Short Link <a class="header-anchor" href="#step-2-define-your-web-short-link" aria-label="Permalink to &quot;Step 2: Define your Web Short Link&quot;">​</a></h3><p>Complete the following steps to define your link:</p><ol><li>Enter your link title in the <strong>Link Title</strong> text field. We recommend standardizing your link names to make them easily searchable.</li><li>Select <strong>Web</strong>.</li><li>Enter the long URL that you want to shorten in the <strong>Destination</strong> text field. This is where your Short Link will redirect to.</li><li>(Optional) Enter a custom link alias (slug/back-half) in the Link Alias text field. You won’t be able to change this once you select <strong>Create Link</strong>.</li></ol><h3 id="step-3-add-analytics-tags-optional" tabindex="-1">Step 3: Add analytics tags (optional) <a class="header-anchor" href="#step-3-add-analytics-tags-optional" aria-label="Permalink to &quot;Step 3: Add analytics tags (optional)&quot;">​</a></h3><p>Add analytics tags to your link to sort and compare performance with your other links.</p><p>You can add analytics tags in two ways in the <strong>Analytics Tags</strong> section:</p><ul><li>Use the drop-downs to select analytics tags that you’ve used in the last 30 days.</li><li>Enter new analytics tags in the text fields and select <strong>Create [ANALYTICS TAG]</strong> to create a new tag.</li></ul><details><summary>Available Tags</summary><p>You can add the following analytics tags to your link:</p><ul><li><strong>Feature</strong>: Should describe the action or product where this link is placed. For UTM, this is typically utm_medium.</li><li><strong>Channel</strong>: Should describe the platform or source from which you are expecting users to click this link. For UTM, this is typically utm_source.</li><li><strong>Campaign</strong>: This can very, but it should describe the theme of the link. For UTM, this is typically utm_campaign.</li><li><strong>Tags</strong>: Tags are a free-form list of meaningful labels that can be used as filters in the Short Links table. Use them to keep your analytics organized.</li></ul></details><div class="info custom-block"><p class="custom-block-title">Note</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>For a tag from a previous Short Link to appear in the drop-down list, the previously created Short Link must be published with at least one click on it.</p></div></div><p>:::</p><h3 id="step-4-add-link-data-optional" tabindex="-1">Step 4: Add link data (optional) <a class="header-anchor" href="#step-4-add-link-data-optional" aria-label="Permalink to &quot;Step 4: Add link data (optional)&quot;">​</a></h3><p>Add any custom link settings, custom analytics tags, or custom redirect logic. You can view <a href="https://help.branch.io/docs/creating-a-deep-link#custom-data" target="_blank" rel="noreferrer">custom data options</a> and <a href="https://help.branch.io/docs/creating-a-deep-link#keys-for-reporting-analytics" target="_blank" rel="noreferrer">advanced analytics tag options</a> in our <a href="./creating-a-deep-link.html">Create Deep Links</a> article.</p><details><summary>Advanced Link Configuration for Web Links</summary><table tabindex="0"><thead><tr><th>Key</th><th>Usage</th></tr></thead><tbody><tr><td><code>$fallback_url_xx</code></td><td>Change the redirect endpoint for all platforms based on a <a href="https://www.iso.org/obp/ui/#search" target="_blank" rel="noreferrer">lower-case Alpha-2 country code</a>. For example, <code>$fallback_url_de=&quot;...&quot;</code> would redirect Germany deep link clicks. You should also set <code>$fallback_url</code> to act as the global redirect in addition to the country-specific ones. WARNING: platform specific redirects (like $ios_url or $desktop_url) are set, they will override the country-specific redirect. Thus, the recommendation is to only use $fallback_url_xx for the country specific redirects and $fallback_url to catch all other users.</td></tr><tr><td><code>$exp_date</code></td><td>Expiry date for the content and any associated link data. Represented as UTC epoch milli second. The maximum date this can be set is 31 days in the future.</td></tr><tr><td><code>$desktop_url</code></td><td>Redirect URL for desktop devices - mobile users will default to the app store.</td></tr><tr><td><code>$ios_url</code></td><td>Change the redirect endpoint for iOS App Store page for your app (set in Link Settings).</td></tr><tr><td><code>$ios_url_xx</code></td><td>Change the redirect endpoint for iOS based on a <a href="https://www.iso.org/obp/ui/#search" target="_blank" rel="noreferrer">lower-case Alpha-2 country code</a>. For example, <code>$ios_url_de=&quot;...&quot;</code> would redirect Germany deep link clicks. You should also set <code>$ios_url</code> to act as the global redirect in addition to the country-specific ones.</td></tr><tr><td><code>$android_url</code></td><td>Change the redirect endpoint for Android Play Store page for your app (set in Link Settings).</td></tr><tr><td><code>$android_url_xx</code></td><td>Change the redirect endpoint for Android based on a <a href="https://www.iso.org/obp/ui/#search" target="_blank" rel="noreferrer">lower-case Alpha-2 country code</a>. For example, <code>$android_url_de=&quot;...&quot;</code> would redirect Germany deep link clicks. You should also set <code>$android_url</code> to act as the global redirect in addition to the country-specific ones.</td></tr><tr><td><code>$ipad_url</code></td><td>Change the redirect endpoint for iPads <code>$ios_url</code> value</td></tr><tr><td><code>$samsung_url</code></td><td>Redirect to Samsung Galaxy Store on Samsung devices. Only link level control. Format should be <code>http://www.samsungapps.com/appquery/appDetail.as?appId=YOUR.PACKAGE.NAME</code></td></tr><tr><td><code>$windows_phone_url</code></td><td>Change the redirect endpoint for Windows OS Windows Phone default URL (set in Link Settings).</td></tr><tr><td><code>$blackberry_url</code></td><td>Change the redirect endpoint for Blackberry OS BlackBerry default URL (set in Link Settings).</td></tr><tr><td><code>$fire_url</code></td><td>Change the redirect endpoint for Amazon Fire OS Fire default URL (set in Link Settings).</td></tr><tr><td><code>$ios_wechat_url</code></td><td>Change the redirect endpoint for WeChat on iOS devices <code>$ios_url</code> value.</td></tr><tr><td><code>$android_wechat_url</code></td><td>Change the redirect endpoint for WeChat on Android devices <code>$android_url</code> value.</td></tr></tbody></table></details><h3 id="step-5-customize-qr-code-optional" tabindex="-1">Step 5: Customize QR code (optional) <a class="header-anchor" href="#step-5-customize-qr-code-optional" aria-label="Permalink to &quot;Step 5: Customize QR code (optional)&quot;">​</a></h3><p>Customize the QR code for this link by selecting the pencil icon above the <strong>QR Preview</strong> section. Learn more in our <a href="./qr-codes-builder.html">Customize QR Codes</a> article.</p><p>Select <strong>Done</strong> to save your customizations.</p><h3 id="step-6-customize-link-preview-optional" tabindex="-1">Step 6: Customize link preview (Optional) <a class="header-anchor" href="#step-6-customize-link-preview-optional" aria-label="Permalink to &quot;Step 6: Customize link preview (Optional)&quot;">​</a></h3><p>Customize the link preview for this link by selecting the pencil icon above the Link Preview section. You can customize the title, description, and background image. This is what your link will look like on social media platforms, messaging apps, and anywhere that supports link previews.</p><p>Select <strong>Done</strong> to save your customizations.</p><h3 id="step-7-finish-creating-your-link" tabindex="-1">Step 7: Finish creating your link <a class="header-anchor" href="#step-7-finish-creating-your-link" aria-label="Permalink to &quot;Step 7: Finish creating your link&quot;">​</a></h3><p>Select <strong>Create Link</strong> to finish creating your link.</p><h2 id="create-an-app-short-link" tabindex="-1">Create an App Short Link <a class="header-anchor" href="#create-an-app-short-link" aria-label="Permalink to &quot;Create an App Short Link&quot;">​</a></h2><p>App Short Links are deep links that take users to specific pages in your app.</p><h3 id="step-1-start-creating-link-1" tabindex="-1">Step 1: Start creating link <a class="header-anchor" href="#step-1-start-creating-link-1" aria-label="Permalink to &quot;Step 1: Start creating link&quot;">​</a></h3><p>Complete the following steps to start creating a link:</p><ol><li>In the Branch Dashboard, select the <strong>Create</strong> button in the top-right corner of the page.</li><li>Select <strong>Link</strong>.</li><li>Select <strong>Short Link</strong>. The <strong>Create Short Link</strong> page will open.</li></ol><h3 id="step-2-define-your-app-short-link" tabindex="-1">Step 2: Define your App Short Link <a class="header-anchor" href="#step-2-define-your-app-short-link" aria-label="Permalink to &quot;Step 2: Define your App Short Link&quot;">​</a></h3><p>Complete the following steps to define your link:</p><ol><li>Enter your link title in the <strong>Link Title</strong> text field. We recommend standardizing your link names to make them easily searchable.</li><li>Select <strong>App</strong>.</li><li>Enter the long URL that you want to shorten in the <strong>Destination</strong> text field. This is where your Short Link will redirect to.</li><li>(Optional) Enter a custom link alias (slug/back-half) in the Link Alias text field. You won’t be able to change this once you select <strong>Create Link</strong>.</li></ol><h3 id="step-3-add-analytics-tags-optional-1" tabindex="-1">Step 3: Add analytics tags (optional) <a class="header-anchor" href="#step-3-add-analytics-tags-optional-1" aria-label="Permalink to &quot;Step 3: Add analytics tags (optional)&quot;">​</a></h3><p>Add analytics tags to your link to sort and compare performance with your other links.</p><p>You can add analytics tags in two ways in the <strong>Analytics Tags</strong> section:</p><ul><li>Use the drop-downs to select analytics tags that you’ve used in the last 30 days.</li><li>Enter new analytics tags in the text fields and select <strong>Create [ANALYTICS TAG]</strong> to create a new tag.</li></ul><details><summary>Available tags</summary><p>You can add the following analytics tags to your link:</p><ul><li><strong>Feature</strong>: Should describe the action or product where this link is placed. For UTM, this is typically utm_medium.</li><li><strong>Channel</strong>: Should describe the platform or source from which you are expecting users to click this link. For UTM, this is typically utm_source.</li><li><strong>Campaign</strong>: This can very, but it should describe the theme of the link. For UTM, this is typically utm_campaign.</li><li><strong>Tags</strong>: Tags are a free-form list of meaningful labels that can be used as filters in the Short Links table. Use them to keep your analytics organized.</li></ul></details><p>For a tag from a previous Short Link to appear in the drop-down list, the previously created Short Link must be published with at least one click on it.</p><h3 id="step-4-add-redirects-optional" tabindex="-1">Step 4: Add redirects (optional) <a class="header-anchor" href="#step-4-add-redirects-optional" aria-label="Permalink to &quot;Step 4: Add redirects (optional)&quot;">​</a></h3><p>To add custom redirects, select the drop-down menu for the platform you want to change and choose a new path.</p><p>Add information about what should happen if you app is not installed when the user clicks on the link. We can take the users to the app store, open a web page, or open a <a href="./deepviews-index.html">Deepview</a>.</p><p>Links you create will automatically inherit redirects on iOS, Android, and Desktop based on <a href="./configure-default-link-behaviors.html">default settings</a> applied to your account.</p><p>You can override those defaults and direct users to specific locations if the app is not installed by adding them in the <strong>Redirects</strong> section.</p><details><summary>Available Redirects</summary><p>You can add the following redirects to your link:</p><ul><li><strong>Default Redirect</strong>: Set at the account level in your <strong>Link Settings</strong>. This is typically set to the relevant mobile stores.</li><li><strong>Web URL</strong>: Send users to a specific web page if they don’t have your app to avoid an unexpected flow to the app store.</li><li><strong>Deepview</strong>: Send users to a specific Deepview you created in the Branch Dashboard. Copy the Deepview key and paste it into this text box. This is useful if you want to present the user with a preview of the content before taking them directly to the app store, but should not be set for the Desktop option.</li></ul></details><h3 id="step-5-add-link-data-optional" tabindex="-1">Step 5: Add link data (optional) <a class="header-anchor" href="#step-5-add-link-data-optional" aria-label="Permalink to &quot;Step 5: Add link data (optional)&quot;">​</a></h3><p>Add any custom link settings, custom analytics tags, or custom redirect logic. You can view <a href="https://help.branch.io/docs/creating-a-deep-link#custom-data" target="_blank" rel="noreferrer">custom data options</a> and <a href="https://help.branch.io/docs/creating-a-deep-link#keys-for-reporting-analytics" target="_blank" rel="noreferrer">advanced analytics tag options</a> in our <a href="./creating-a-deep-link.html">Create Deep Links</a> article.</p><h3 id="step-6-customize-qr-code-optional" tabindex="-1">Step 6: Customize QR code (optional) <a class="header-anchor" href="#step-6-customize-qr-code-optional" aria-label="Permalink to &quot;Step 6: Customize QR code (optional)&quot;">​</a></h3><p>Customize the QR code for this link by selecting the pencil icon above the <strong>QR Preview</strong> section. Learn more in our <a href="./qr-codes-builder.html">Customize QR Codes</a> article.</p><p>Select <strong>Done</strong> to save your customizations.</p><h3 id="step-7-customize-link-preview-optional" tabindex="-1">Step 7: Customize link preview (optional) <a class="header-anchor" href="#step-7-customize-link-preview-optional" aria-label="Permalink to &quot;Step 7: Customize link preview (optional)&quot;">​</a></h3><p>Customize the link preview for this link by selecting the pencil icon above the Link Preview section. You can customize the title, description, and background image. This is what your link will look like on social media platforms, messaging apps, and anywhere that supports link previews.</p><p>Select <strong>Done</strong> to save your customizations.</p><h3 id="step-8-finish-creating-your-link" tabindex="-1">Step 8: Finish creating your link <a class="header-anchor" href="#step-8-finish-creating-your-link" aria-label="Permalink to &quot;Step 8: Finish creating your link&quot;">​</a></h3><p>Select <strong>Create Link</strong> to finish creating your link.</p><h2 id="view-and-manage-links" tabindex="-1">View and manage links <a class="header-anchor" href="#view-and-manage-links" aria-label="Permalink to &quot;View and manage links&quot;">​</a></h2><p>You can use LinkHub to manage and view your Short Links. You can learn more in our <a href="./linkhub.html">LinkHub</a> article. With Activation you’ll see separate <strong>Web Short Links</strong> and <strong>App Short Links</strong> tabs.</p><p>You can also view Web Short Links on the <strong>Summary</strong> page in the Branch Dashboard on the <strong>All Data</strong> and <strong>Short Links</strong> tabs.</p><h2 id="analyze-link-performance" tabindex="-1">Analyze link performance <a class="header-anchor" href="#analyze-link-performance" aria-label="Permalink to &quot;Analyze link performance&quot;">​</a></h2><h3 id="linkhub" tabindex="-1">LinkHub <a class="header-anchor" href="#linkhub" aria-label="Permalink to &quot;LinkHub&quot;">​</a></h3><p>In LinkHub, you can view how many clicks your links have received. Select the <strong>Clicks</strong> column in the table to sort by most clicks or least clicks. You can learn more in our <a href="./linkhub.html">LinkHub</a> article.</p><h3 id="overview-page" tabindex="-1">Overview page <a class="header-anchor" href="#overview-page" aria-label="Permalink to &quot;Overview page&quot;">​</a></h3><p>On the <strong>Overview</strong> page, use the <strong>Summary</strong> or <strong>Sources</strong> tabs to view relevant analytics for your links. Read our <a href="./branch-summary-page.html">Overview Page</a> article to learn more about comparing and filtering results.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>Can I convert App Short Links to Web Short Links and the other way around?</summary><p>Yes. If you have the newest version of the Branch SDK, Web Short Links will open in an in-app web view.</p></details>',85)])])}const g=t(r,[["render",n]]);export{u as __pageData,g as default};
